const db = cloud.database()

function startOfDayCN(ts) {
  const offset = 8 * 60 * 60 * 1000
  const d = new Date(ts + offset)
  d.setUTCHours(0, 0, 0, 0)
  return d.getTime() - offset
}

function dateKeyCN(ts) {
  const offset = 8 * 60 * 60 * 1000
  return new Date(ts + offset).toISOString().slice(0, 10)
}

function normalizeTypes(input) {
  if (Array.isArray(input)) return input.map((x) => String(x || '').trim()).filter(Boolean)
  const s = String(input || '').trim()
  if (!s) return []
  if (s.startsWith('[') && s.endsWith(']')) {
    try {
      const arr = JSON.parse(s)
      return Array.isArray(arr) ? arr.map((x) => String(x || '').trim()).filter(Boolean) : []
    } catch { return [] }
  }
  if (s.includes(',')) return s.split(',').map(x => String(x || '').trim()).filter(Boolean)
  return [s]
}

