import React, { useEffect, useMemo, useState } from 'react'
import { Button, Card, DatePicker, Space, Statistic, Table, message } from 'antd'
import ReactECharts from 'echarts-for-react'
import { getChallengeModeTrend } from '../api/cloud'

const DAY_MS = 24 * 60 * 60 * 1000

function startOfDayCN(ts: number) {
  const offset = 8 * 60 * 60 * 1000
  const d = new Date(ts + offset)
  d.setUTCHours(0, 0, 0, 0)
  return d.getTime() - offset
}

function getRecentRange(days: number) {
  const endDay = startOfDayCN(Date.now()) + DAY_MS - 1
  const startDay = endDay - (Math.max(1, days) - 1) * DAY_MS
  return [startDay, endDay] as const
}

export default function ChallengeModeTrend() {
  const [loading, setLoading] = useState(false)
  const [range, setRange] = useState<[any, any] | null>(null)
  const [data, setData] = useState<Array<{
    key: string
    date: string
    hardCount: number
    easyCount: number
    hardAdCount: number
    easyAdCount: number
  }>>([])
  const [summary, setSummary] = useState({
    hardCount: 0,
    easyCount: 0,
    hardAdCount: 0,
    easyAdCount: 0,
    activeHardDays: 0,
    activeEasyDays: 0,
    totalRecords: 0,
  })

  const load = async (nextRange?: [number, number]) => {
    const defaultRange = getRecentRange(7)
    const startTime = nextRange?.[0] ?? (range?.[0] ? range[0].valueOf() : defaultRange[0])
    const endTime = nextRange?.[1] ?? (range?.[1] ? range[1].valueOf() : defaultRange[1])
    if (!startTime || !endTime) {
      message.warning('请选择统计时间范围')
      return
    }
    setLoading(true)
    try {
      const res = await getChallengeModeTrend({ startTime, endTime })
      if (!res || res.ok === false) throw new Error('统计失败')
      setData(Array.isArray(res.byDay) ? res.byDay : [])
      setSummary({
        hardCount: Number(res.summary?.hardCount || 0),
        easyCount: Number(res.summary?.easyCount || 0),
        hardAdCount: Number(res.summary?.hardAdCount || 0),
        easyAdCount: Number(res.summary?.easyAdCount || 0),
        activeHardDays: Number(res.summary?.activeHardDays || 0),
        activeEasyDays: Number(res.summary?.activeEasyDays || 0),
        totalRecords: Number(res.totalRecords || 0),
      })
    } catch (e: any) {
      message.error(e?.message || '统计失败')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    load(getRecentRange(7) as [number, number])
  }, [])

  const hardOption = useMemo(() => ({
    tooltip: { trigger: 'axis' },
    legend: { data: ['困难模式参与次数', '困难模式广告观看次数'] },
    grid: { left: 56, right: 56, top: 48, bottom: 72 },
    xAxis: {
      type: 'category',
      data: data.map(item => item.date),
      axisLabel: { rotate: data.length > 12 ? 35 : 0 },
    },
    yAxis: [
      { type: 'value', name: '参与次数' },
      { type: 'value', name: '广告次数', splitLine: { show: false } },
    ],
    series: [
      {
        name: '困难模式参与次数',
        type: 'bar',
        data: data.map(item => Number(item.hardCount || 0)),
        itemStyle: { color: '#1677ff' },
        barMaxWidth: 28,
      },
      {
        name: '困难模式广告观看次数',
        type: 'line',
        yAxisIndex: 1,
        smooth: true,
        data: data.map(item => Number(item.hardAdCount || 0)),
        itemStyle: { color: '#fa8c16' },
      },
    ],
  }), [data])

  const easyOption = useMemo(() => ({
    tooltip: { trigger: 'axis' },
    legend: { data: ['简单模式参与次数', '简单模式广告观看次数'] },
    grid: { left: 56, right: 56, top: 48, bottom: 72 },
    xAxis: {
      type: 'category',
      data: data.map(item => item.date),
      axisLabel: { rotate: data.length > 12 ? 35 : 0 },
    },
    yAxis: [
      { type: 'value', name: '参与次数' },
      { type: 'value', name: '广告次数', splitLine: { show: false } },
    ],
    series: [
      {
        name: '简单模式参与次数',
        type: 'bar',
        data: data.map(item => Number(item.easyCount || 0)),
        itemStyle: { color: '#52c41a' },
        barMaxWidth: 28,
      },
      {
        name: '简单模式广告观看次数',
        type: 'line',
        yAxisIndex: 1,
        smooth: true,
        data: data.map(item => Number(item.easyAdCount || 0)),
        itemStyle: { color: '#722ed1' },
      },
    ],
  }), [data])

  return (
    <div>
      <div style={{ fontWeight: 700, fontSize: 18, marginBottom: 12 }}>挑战模式统计</div>

      <Card style={{ marginBottom: 12 }}>
        <Space wrap>
          <DatePicker.RangePicker value={range as any} format='YYYY-MM-DD' onChange={(v) => setRange(v as any)} />
          <Button onClick={() => { setRange(null); load(getRecentRange(7) as [number, number]) }}>近7天</Button>
          <Button onClick={() => { setRange(null); load(getRecentRange(30) as [number, number]) }}>近30天</Button>
          <Button onClick={() => { setRange(null); load(getRecentRange(90) as [number, number]) }}>近90天</Button>
          <Button type='primary' loading={loading} onClick={() => load()}>统计</Button>
        </Space>
      </Card>

      <Space wrap size={12} style={{ marginBottom: 12 }}>
        <Card><Statistic title='困难模式参与总次数' value={summary.hardCount} /></Card>
        <Card><Statistic title='简单模式参与总次数' value={summary.easyCount} /></Card>
        <Card><Statistic title='困难模式广告观看总次数' value={summary.hardAdCount} /></Card>
        <Card><Statistic title='简单模式广告观看总次数' value={summary.easyAdCount} /></Card>
        <Card><Statistic title='困难模式活跃天数' value={summary.activeHardDays} /></Card>
        <Card><Statistic title='简单模式活跃天数' value={summary.activeEasyDays} /></Card>
        <Card><Statistic title='命中记录总数' value={summary.totalRecords} /></Card>
      </Space>

      <Card style={{ marginBottom: 12 }}>
        <div style={{ fontWeight: 600, marginBottom: 12 }}>困难模式趋势图</div>
        <ReactECharts option={hardOption} style={{ height: Math.max(360, data.length > 20 ? 440 : 380) }} showLoading={loading} notMerge />
      </Card>

      <Card style={{ marginBottom: 12 }}>
        <div style={{ fontWeight: 600, marginBottom: 12 }}>简单模式趋势图</div>
        <ReactECharts option={easyOption} style={{ height: Math.max(320, data.length > 20 ? 400 : 360) }} showLoading={loading} notMerge />
      </Card>

      <Card>
        <Table
          rowKey='key'
          loading={loading}
          dataSource={data}
          pagination={false}
          columns={[
            { title: '日期', dataIndex: 'date' },
