function startOfDayCN(ts) {
  const offset = 8 * 60 * 60 * 1000
  const d = new Date(ts + offset)
  d.setUTCHours(0, 0, 0, 0)
  return d.getTime() - offset
}

function dateKeyCN(ts) {
  const offset = 8 * 60 * 60 * 1000
  return new Date(ts + offset).toISOString().slice(0, 10)
}

function normalizeTypes(input) {
  if (Array.isArray(input)) return input.map((x) => String(x || '').trim()).filter(Boolean)
  const s = String(input || '').trim()
  if (!s) return []
  if (s.startsWith('[') && s.endsWith(']')) {
    try {
      const arr = JSON.parse(s)
      return Array.isArray(arr) ? arr.map((x) => String(x || '').trim()).filter(Boolean) : []
    } catch { return [] }
  }
  if (s.includes(',')) return s.split(',').map(x => String(x || '').trim()).filter(Boolean)
  return [s]
}

exports.main = async (event) => {
  const { userId, level, progressGte, progressGt, isHard, page = 1, pageSize = 20, action, days = 7, type = 'challenge' } = event || {}
  try {
    if (String(action || '') === 'actionPath') {
      const _ = db.command
      const openid = String((event && event.openid) || '').trim()
      if (!openid) return { ok: false, error: 'missing_openid', list: [], total: 0 }
      const p = Math.max(1, Number(event.page || 1) || 1)
      const ps = Math.max(1, Math.min(200, Number(event.pageSize || 50) || 50))
      const skip = (p - 1) * ps
      const where = { openid }
      const st = (event.startTime === 0 || event.startTime) ? Number(event.startTime) : null
      const et = (event.endTime === 0 || event.endTime) ? Number(event.endTime) : null
      if (Number.isFinite(st) || Number.isFinite(et)) {
        where.createTime = _.and(_.gte(Number.isFinite(st) ? st : 0), _.lte(Number.isFinite(et) ? et : Date.now()))
      }
      const t = String(event.type || '').trim()
      if (t) where.type = t
      const sortDir = String(event.order || 'asc').toLowerCase() === 'desc' ? 'desc' : 'asc'
      const coll = db.collection('action')
      const query = coll.where(where)
      const countRes = await query.count()
      const total = (countRes && typeof countRes.total === 'number') ? countRes.total : 0
      const res = await query.orderBy('createTime', sortDir).skip(skip).limit(ps).get()
      const list = (res.data || []).map((d) => ({
        id: d._id || d.id,
        openid: d.openid || '',
        type: d.type || '',
        createTime: d.createTime || 0,
        createTimeStr: d.createTimeStr || '',
        moreInfo: d.moreInfo || '',
      }))
      return { ok: true, list, total }
    }
    if (String(action || '') === 'actionTrends') {
      const _ = db.command
      const $ = db.command.aggregate
      const st = (event.startTime === 0 || event.startTime) ? Number(event.startTime) : null
      const et = (event.endTime === 0 || event.endTime) ? Number(event.endTime) : null
      if (!Number.isFinite(st) || !Number.isFinite(et) || st > et) return { ok: false, error: 'invalid_time_range' }
      const maxTypes = Math.max(1, Number(event.maxTypes) || 5)
      const dayMs = 24 * 60 * 60 * 1000
      const startDay = startOfDayCN(st)
      const endDay = startOfDayCN(et) + dayMs - 1
