          .sort({ cnt: -1 })
          .limit(maxTypes)
          .end()
        typeList = (topAgg && topAgg.list ? topAgg.list : []).map((r) => String(r && r._id || '').trim()).filter(Boolean)
      }
      if (!typeList.length) return { ok: true, start: startDay, end: endDay, days: nDays, types: [], series: [] }
      const seriesMap = new Map()
      for (const t of typeList) seriesMap.set(t, [])
      for (let i = 0; i < nDays; i++) {
        const dayStart = startDay + i * dayMs
        const dayEnd = dayStart + dayMs - 1
        const date = dateKeyCN(dayStart)
        const res = await db.collection('action').aggregate()
          .match({
            createTime: _.and(_.gte(dayStart), _.lte(dayEnd)),
            type: _.in(typeList),
          })
          .group({ _id: '$type', cnt: $.sum(1) })
          .end()
        const rows = (res && res.list) ? res.list : []
