import { Table, Card, Space, Input, Button, Select, Tag, message, DatePicker, Radio } from 'antd'
import React, { useEffect, useState } from 'react'
import dayjs from 'dayjs'
import { listRecords } from '../api/cloud'
import app, { ensureLogin } from '../cloudbase'

export default function RecordManage() {
  const [userId, setUserId] = useState('')
  const [mode, setMode] = useState<'easy' | 'hard'>('easy')
  const [dateValue, setDateValue] = useState<dayjs.Dayjs | null>(null)
  const [levelOptions, setLevelOptions] = useState<{ label: string; value: string }[]>([])
  const [level, setLevel] = useState('')
  const [levelLoading, setLevelLoading] = useState(false)
  const [progressGte, setProgressGte] = useState('')
  const [data, setData] = useState<any[]>([])
  const [loading, setLoading] = useState(false)
  const [page, setPage] = useState(1)
  const [pageSize, setPageSize] = useState(20)
  const [total, setTotal] = useState(0)

  // 当日期或模式变化时，自动拉取该天该模式下的关卡列表
  useEffect(() => {
    let cancelled = false
    const loadLevels = async () => {
      setLevel('')
      setLevelOptions([])
      if (!dateValue) return
      const dayStr = dateValue.format('YYYY-MM-DD')
      const collectionName = mode === 'easy' ? 'easyLevels' : 'levels'
      setLevelLoading(true)
      try {
        await ensureLogin()
        const db = app.database()
        const res: any = await db.collection(collectionName).where({ time: dayStr }).limit(1000).get()
        const list = Array.isArray(res?.data) ? res.data : []
        if (cancelled) return
        const options = list.map((doc: any, idx: number) => {
          const id = String(doc._id)
          const label = doc.level != null ? `第${doc.level}关 (${id})` : `${idx + 1}. ${id}`
          return { label, value: id }
        })
        setLevelOptions(options)
        if (options.length === 0) message.info('该日期下未找到关卡')
      } catch (e: any) {
        if (!cancelled) message.error(e?.message || '加载关卡失败')
      } finally {
        if (!cancelled) setLevelLoading(false)
      }
    }
    loadLevels()
    return () => { cancelled = true }
  }, [dateValue, mode])

  const query = async (p = 1, ps = pageSize) => {
    setPage(p)
    setPageSize(ps)
    setLoading(true)
    try {
      const normalizedProgressGte = String(progressGte || '').trim().replace(/%/g, '')
      const parsedProgressGte = Number(normalizedProgressGte)
      const r = await listRecords({
        userId,
        level,
        progressGte: normalizedProgressGte !== '' && Number.isFinite(parsedProgressGte) ? parsedProgressGte : undefined,
        isHard: mode === 'hard',
        page: p,
        pageSize: ps
      })
      if (r && r.ok) { setData(r.list || []); setTotal(r.total || 0) } else message.error('查询失败')
    } catch { message.error('查询失败') }
    finally { setLoading(false) }
  }

  return (
    <div>
      <div style={{ fontWeight: 700, fontSize: 18, marginBottom: 12 }}>玩家闯关记录</div>
      <Card>
        <Space style={{ marginBottom: 12 }} wrap>
          <Input style={{ width: 240 }} placeholder='用户ID' value={userId} onChange={e => setUserId(e.target.value)} />
          <Radio.Group value={mode} onChange={(e) => setMode(e.target.value)}>
            <Radio.Button value='easy'>简单模式</Radio.Button>
            <Radio.Button value='hard'>困难模式</Radio.Button>
          </Radio.Group>
          <DatePicker
            value={dateValue}
            onChange={(d) => setDateValue(d)}
            placeholder='选择关卡日期'
            style={{ width: 160 }}
            allowClear
          />
          <Select
            style={{ width: 260 }}
            placeholder={dateValue ? '选择关卡' : '请先选择日期'}
            value={level || undefined}
            onChange={(v) => setLevel(v || '')}
            options={levelOptions}
            loading={levelLoading}
            disabled={!dateValue || levelOptions.length === 0}
            allowClear
            showSearch
            optionFilterProp='label'
          />
          <Input style={{ width: 200 }} placeholder='进度大于等于(%)，如 80' value={progressGte} onChange={e => setProgressGte(e.target.value)} />
          <Button type='primary' onClick={() => query(1, pageSize)}>查询</Button>
        </Space>
        <Table rowKey='_id' loading={loading} dataSource={data}
          pagination={{ current: page, pageSize, total, showSizeChanger: true }}
          onChange={(p) => { setPage(p.current || 1); setPageSize(p.pageSize || 20); query(p.current || 1, p.pageSize || 20) }}
          columns={[
            { title: '用户ID', dataIndex: 'userId' },
            { title: '关卡', dataIndex: 'level' },
            { title: '进度', dataIndex: 'progress' },
            { title: 'isHard', dataIndex: 'isHard', render: (v: boolean) => <Tag color={v ? 'red' : 'default'}>{v ? '是' : '否'}</Tag> },
            { title: '星星', dataIndex: 'star' },
            { title: '耗时(ms)', dataIndex: 'timeMs' },
            { title: '类型', dataIndex: 'type' },
            { title: '广告', dataIndex: 'ad' },
            { title: '分享', dataIndex: 'share' },
            { title: '经验', dataIndex: 'exp' },
            { title: '创建时间', dataIndex: 'createTime', render: (t: number) => t ? new Date(t).toLocaleString() : '-' },
          ]}
        />
      </Card>
    </div>
  )
}

