router.post("/challenge-mode-trend", async (req: Request, res: Response) => {
  try {
    const body = req.body || {}
    const now = Date.now()
    const dayMs = 86400000
    const st = Number.isFinite(Number(body.startTime)) ? Number(body.startTime) : now - 6 * dayMs
    const et = snapToEndOfDayCN(Number.isFinite(Number(body.endTime)) ? Number(body.endTime) : now)

    const result = await getClient().query({
      query: `
        SELECT
          toDate(create_time, 'Asia/Shanghai') AS date,
          countIf(is_hard = 1) AS hard_count,
          countIf(is_hard = 0) AS easy_count,
          sumIf(ad, is_hard = 1) AS hard_ad_count,
          sumIf(ad, is_hard = 0) AS easy_ad_count
        FROM game_records
        WHERE type = 'challenge' AND is_robot = 0
          AND create_time BETWEEN fromUnixTimestamp64Milli({st: UInt64}) AND fromUnixTimestamp64Milli({et: UInt64})
