      const ha = Number(r.hard_ad_count || 0), ea = Number(r.easy_ad_count || 0)
      totalRecords += hc + ec
      summary.hardCount += hc; summary.easyCount += ec
      summary.hardAdCount += ha; summary.easyAdCount += ea
      if (hc > 0) summary.activeHardDays++
      if (ec > 0) summary.activeEasyDays++
      const d = String(r.date)
      return { key: d, date: d, hardCount: hc, easyCount: ec, hardAdCount: ha, easyAdCount: ea }
    })

    res.json({ ok: true, startTime: st, endTime: et, totalRecords, byDay, summary })
  } catch (e: any) {
    console.error("[analytics/challenge-mode-trend]", e?.message || e)
    res.status(500).json({ ok: false, error: e?.message || "query_failed" })
