import React, { useEffect, useMemo, useState } from 'react'
import { Button, Card, DatePicker, Space, Statistic, Table, message } from 'antd'
import ReactECharts from 'echarts-for-react'
import { getSoloModeTrend } from '../api/cloud'

const DAY_MS = 24 * 60 * 60 * 1000

function startOfDayCN(ts: number) {
  const offset = 8 * 60 * 60 * 1000
  const d = new Date(ts + offset)
  d.setUTCHours(0, 0, 0, 0)
  return d.getTime() - offset
}

function getRecentRange(days: number) {
  const endDay = startOfDayCN(Date.now()) + DAY_MS - 1
  const startDay = endDay - (Math.max(1, days) - 1) * DAY_MS
  return [startDay, endDay] as const
}

export default function SoloModeTrend() {
  const [loading, setLoading] = useState(false)
  const [range, setRange] = useState<[any, any] | null>(null)
  const [data, setData] = useState<Array<{
    key: string
    date: string
    count: number
    normalEndCount: number
    abnormalEndCount: number
  }>>([])
  const [summary, setSummary] = useState({
    count: 0,
    normalEndCount: 0,
    abnormalEndCount: 0,
    activeDays: 0,
    totalRecords: 0,
  })

  const load = async (nextRange?: [number, number]) => {
    const defaultRange = getRecentRange(7)
    const startTime = nextRange?.[0] ?? (range?.[0] ? range[0].valueOf() : defaultRange[0])
    const endTime = nextRange?.[1] ?? (range?.[1] ? range[1].valueOf() : defaultRange[1])
    if (!startTime || !endTime) {
      message.warning('请选择统计时间范围')
      return
    }
    setLoading(true)
    try {
      const res = await getSoloModeTrend({ startTime, endTime })
      if (!res || res.ok === false) throw new Error(res?.error || '统计失败')
      setData(Array.isArray(res.byDay) ? res.byDay : [])
      setSummary({
        count: Number(res.summary?.count || 0),
        normalEndCount: Number(res.summary?.normalEndCount || 0),
        abnormalEndCount: Number(res.summary?.abnormalEndCount || 0),
        activeDays: Number(res.summary?.activeDays || 0),
        totalRecords: Number(res.totalRecords || 0),
      })
    } catch (e: any) {
      message.error(e?.message || '统计失败')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    load(getRecentRange(7) as [number, number])
  }, [])

  const countOption = useMemo(() => ({
    tooltip: { trigger: 'axis' },
    legend: { data: ['Solo模式完成对局数'] },
    grid: { left: 56, right: 32, top: 48, bottom: 72 },
    xAxis: {
      type: 'category',
      data: data.map(item => item.date),
      axisLabel: { rotate: data.length > 12 ? 35 : 0 },
    },
    yAxis: [{ type: 'value', name: '对局数' }],
    series: [
      {
        name: 'Solo模式完成对局数',
        type: 'bar',
        data: data.map(item => Number(item.count || 0)),
        itemStyle: { color: '#1677ff' },
        barMaxWidth: 28,
      },
    ],
  }), [data])

  const normalEndOption = useMemo(() => ({
    tooltip: { trigger: 'axis' },
    legend: { data: ['正常结束数', '非正常结束数'] },
    grid: { left: 56, right: 56, top: 48, bottom: 72 },
    xAxis: {
      type: 'category',
      data: data.map(item => item.date),
      axisLabel: { rotate: data.length > 12 ? 35 : 0 },
    },
    yAxis: [{ type: 'value', name: '次数' }],
    series: [
      {
        name: '正常结束数',
        type: 'line',
        smooth: true,
        data: data.map(item => Number(item.normalEndCount || 0)),
        itemStyle: { color: '#52c41a' },
      },
      {
        name: '非正常结束数',
        type: 'line',
        smooth: true,
        data: data.map(item => Number(item.abnormalEndCount || 0)),
        itemStyle: { color: '#ff4d4f' },
      },
    ],
  }), [data])

  return (
    <div>
      <div style={{ fontWeight: 700, fontSize: 18, marginBottom: 12 }}>Solo模式统计</div>

      <Card style={{ marginBottom: 12 }}>
        <Space wrap>
          <DatePicker.RangePicker value={range as any} format='YYYY-MM-DD' onChange={(v) => setRange(v as any)} />
          <Button onClick={() => { setRange(null); load(getRecentRange(7) as [number, number]) }}>近7天</Button>
          <Button onClick={() => { setRange(null); load(getRecentRange(30) as [number, number]) }}>近30天</Button>
          <Button onClick={() => { setRange(null); load(getRecentRange(90) as [number, number]) }}>近90天</Button>
          <Button type='primary' loading={loading} onClick={() => load()}>统计</Button>
        </Space>
      </Card>

      <Space wrap size={12} style={{ marginBottom: 12 }}>
        <Card><Statistic title='完成对局总数' value={summary.count} /></Card>
        <Card><Statistic title='正常结束总数' value={summary.normalEndCount} /></Card>
        <Card><Statistic title='非正常结束总数' value={summary.abnormalEndCount} /></Card>
        <Card><Statistic title='活跃天数' value={summary.activeDays} /></Card>
        <Card><Statistic title='命中记录总数' value={summary.totalRecords} /></Card>
      </Space>

      <Card style={{ marginBottom: 12 }}>
        <div style={{ fontWeight: 600, marginBottom: 12 }}>Solo模式趋势图</div>
        <ReactECharts option={countOption} style={{ height: Math.max(320, data.length > 20 ? 400 : 360) }} showLoading={loading} notMerge />
      </Card>

      <Card style={{ marginBottom: 12 }}>
        <div style={{ fontWeight: 600, marginBottom: 12 }}>Solo模式结束情况趋势图</div>
        <ReactECharts option={normalEndOption} style={{ height: Math.max(320, data.length > 20 ? 400 : 360) }} showLoading={loading} notMerge />
      </Card>

      <Card>
        <Table
          rowKey='key'
          loading={loading}
          dataSource={data}
          pagination={false}
          columns={[
            { title: '日期', dataIndex: 'date' },
            { title: '完成对局数', dataIndex: 'count' },
            { title: '正常结束数', dataIndex: 'normalEndCount' },
            { title: '非正常结束数', dataIndex: 'abnormalEndCount' },
          ]}
        />
      </Card>
    </div>
  )
}

