import React, { useEffect, useMemo, useState } from 'react'
import { Button, Card, DatePicker, InputNumber, Select, Space, Statistic, Table, Tag, message } from 'antd'
import ReactECharts from 'echarts-for-react'
import { getLevelActiveTrend } from '../api/cloud'

const DAY_MS = 24 * 60 * 60 * 1000

type ModeType = 'all' | 'challenge' | 'clearance'
type HardMode = 'all' | 'hard' | 'easy'

function startOfDayCN(ts: number) {
  const offset = 8 * 60 * 60 * 1000
  const d = new Date(ts + offset)
  d.setUTCHours(0, 0, 0, 0)
  return d.getTime() - offset
}

function getRecentRange(days: number) {
  const endDay = startOfDayCN(Date.now()) + DAY_MS - 1
  const startDay = endDay - (Math.max(1, days) - 1) * DAY_MS
  return [startDay, endDay] as const
}

function typeLabel(type: string) {
  if (type === 'challenge') return '挑战模式'
  if (type === 'clearance') return '闯关模式'
  return type || '-'
}

export default function LevelActiveTrend() {
  const [loading, setLoading] = useState(false)
  const [range, setRange] = useState<[any, any] | null>(null)
  const [minUsers, setMinUsers] = useState(10)
  const [type, setType] = useState<ModeType>('all')
  const [hardMode, setHardMode] = useState<HardMode>('all')
  const [data, setData] = useState<Array<{ key: string; date: string; activeUsers: number; recordCount: number; activeLevelCount: number }>>([])
  const [topLevels, setTopLevels] = useState<Array<{ key: string; type: string; level: string; totalUsers: number; totalRecords: number }>>([])
  const [summary, setSummary] = useState({
    activeUsers: 0,
    recordCount: 0,
    qualifiedLevelCount: 0,
    activeDays: 0,
  })

  const load = async (nextRange?: [number, number]) => {
    const defaultRange = getRecentRange(30)
    const startTime = nextRange?.[0] ?? (range?.[0] ? range[0].valueOf() : defaultRange[0])
    const endTime = nextRange?.[1] ?? (range?.[1] ? range[1].valueOf() : defaultRange[1])
    if (!startTime || !endTime) {
      message.warning('请选择统计时间范围')
      return
    }
    setLoading(true)
    try {
      const res = await getLevelActiveTrend({
        startTime,
        endTime,
        minUsers,
        type,
        hardMode: type === 'challenge' ? hardMode : 'all',
      })
      if (!res || res.ok === false) throw new Error(res?.error || '统计失败')
      setData(Array.isArray(res.byDay) ? res.byDay : [])
      setTopLevels(Array.isArray(res.topLevels) ? res.topLevels : [])
      setSummary({
        activeUsers: Number(res.summary?.activeUsers || 0),
        recordCount: Number(res.summary?.recordCount || 0),
        qualifiedLevelCount: Number(res.summary?.qualifiedLevelCount || 0),
        activeDays: Number(res.summary?.activeDays || 0),
      })
    } catch (e: any) {
      message.error(e?.message || '统计失败')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    load(getRecentRange(30) as [number, number])
  }, [])

  const trendOption = useMemo(() => ({
    tooltip: { trigger: 'axis' },
    legend: { data: ['活跃人数', '记录数', '活跃关卡数'] },
    grid: { left: 56, right: 64, top: 48, bottom: 72 },
    xAxis: {
      type: 'category',
      data: data.map(item => item.date),
      axisLabel: { rotate: data.length > 12 ? 35 : 0 },
    },
    yAxis: [
      { type: 'value', name: '人数/关卡' },
      { type: 'value', name: '记录数', splitLine: { show: false } },
    ],
    series: [
      {
        name: '活跃人数',
        type: 'line',
        smooth: true,
        data: data.map(item => Number(item.activeUsers || 0)),
        itemStyle: { color: '#1677ff' },
        areaStyle: { color: 'rgba(22, 119, 255, 0.12)' },
      },
      {
        name: '记录数',
        type: 'bar',
        yAxisIndex: 1,
        data: data.map(item => Number(item.recordCount || 0)),
        itemStyle: { color: '#52c41a' },
        barMaxWidth: 28,
      },
      {
        name: '活跃关卡数',
        type: 'line',
        smooth: true,
        data: data.map(item => Number(item.activeLevelCount || 0)),
        itemStyle: { color: '#fa8c16' },
      },
    ],
  }), [data])

  return (
    <div>
      <div style={{ fontWeight: 700, fontSize: 18, marginBottom: 12 }}>高活跃关卡趋势</div>

      <Card style={{ marginBottom: 12 }}>
        <Space wrap>
          <DatePicker.RangePicker value={range as any} format='YYYY-MM-DD' onChange={(v) => setRange(v as any)} />
          <Select
            style={{ width: 140 }}
            value={type}
            onChange={(v: ModeType) => {
              setType(v)
              if (v !== 'challenge') setHardMode('all')
            }}
            options={[
              { value: 'all', label: '全部模式' },
              { value: 'challenge', label: '挑战模式' },
              { value: 'clearance', label: '闯关模式' },
            ]}
          />
          <Select
            style={{ width: 140 }}
            value={hardMode}
            disabled={type !== 'challenge'}
            onChange={(v: HardMode) => setHardMode(v)}
            options={[
              { value: 'all', label: '全部难度' },
              { value: 'hard', label: '困难模式' },
              { value: 'easy', label: '简单模式' },
            ]}
          />
          <InputNumber
            min={1}
            max={1000000}
            value={minUsers}
            onChange={(v) => setMinUsers(typeof v === 'number' ? v : 10)}
            addonBefore='关卡人数 >'
            style={{ width: 180 }}
          />
          <Button onClick={() => { setRange(null); load(getRecentRange(7) as [number, number]) }}>近7天</Button>
          <Button onClick={() => { setRange(null); load(getRecentRange(30) as [number, number]) }}>近30天</Button>
          <Button onClick={() => { setRange(null); load(getRecentRange(90) as [number, number]) }}>近90天</Button>
          <Button type='primary' loading={loading} onClick={() => load()}>统计</Button>
        </Space>
      </Card>

      <Space wrap size={12} style={{ marginBottom: 12 }}>
        <Card><Statistic title='命中关卡数' value={summary.qualifiedLevelCount} /></Card>
        <Card><Statistic title='去重活跃人数' value={summary.activeUsers} /></Card>
        <Card><Statistic title='命中记录数' value={summary.recordCount} /></Card>
        <Card><Statistic title='活跃天数' value={summary.activeDays} /></Card>
      </Space>

      <Card style={{ marginBottom: 12 }}>
        <div style={{ fontWeight: 600, marginBottom: 12 }}>按天活跃趋势</div>
        <ReactECharts option={trendOption} style={{ height: Math.max(360, data.length > 20 ? 460 : 380) }} showLoading={loading} notMerge />
      </Card>

      <Card style={{ marginBottom: 12 }}>
        <Table
          rowKey='key'
          loading={loading}
          dataSource={data}
          pagination={false}
          columns={[
            { title: '日期', dataIndex: 'date' },
            { title: '活跃人数', dataIndex: 'activeUsers' },
            { title: '记录数', dataIndex: 'recordCount' },
            { title: '活跃关卡数', dataIndex: 'activeLevelCount' },
          ]}
        />
      </Card>

      <Card>
        <Table
          rowKey='key'
          loading={loading}
          dataSource={topLevels}
          pagination={{ pageSize: 20, showSizeChanger: false }}
          columns={[
            { title: '模式', dataIndex: 'type', render: (v: string) => <Tag>{typeLabel(v)}</Tag> },
            { title: '关卡', dataIndex: 'level' },
            { title: '累计去重人数', dataIndex: 'totalUsers', sorter: (a, b) => a.totalUsers - b.totalUsers },
            { title: '累计记录数', dataIndex: 'totalRecords', sorter: (a, b) => a.totalRecords - b.totalRecords },
          ]}
        />
      </Card>
    </div>
  )
}

